sql:
SELECT COUNT(*) 
FROM video_revisions 
WHERE strftime('%Y', revision_date) = '2022';

SELECT revision_date
FROM video_revisions
WHERE revision_date LIKE '2022-%';

SELECT video_id, COUNT(revision_id) AS revision_count
FROM video_revisions
GROUP BY video_id;

SELECT video_id, SUM(view_count) AS total_views, SUM(like_count) AS total_likes
FROM video_engagement
GROUP BY video_id;

SELECT ve.video_id, ve.view_count
FROM video_engagement AS ve
WHERE ve.view_count > 10000;

SELECT category_id, COUNT(video_id) AS video_count
FROM video_categories
GROUP BY category_id;

SELECT video_id
FROM videos
WHERE channel_id = '0';

SELECT video_id
FROM video_engagement
WHERE view_count = (SELECT MAX(view_count) FROM video_engagement);

SELECT video_id, view_count
FROM video_engagement
ORDER BY view_count DESC;

SELECT SUM(view_count + like_count + comment_count) AS total_engagements
FROM video_engagement
WHERE video_id = 1;
